css:
.loader {
  display: grid;
  grid-template-columns: 42px 108px;
  gap: 8px 12px;
  align-items: center;
}
.loader b,
.loader i {
  display: block;
  background: linear-gradient(90deg, rgba(99,102,241,.12), rgba(99,102,241,.32), rgba(99,102,241,.12));
  background-size: 220% 100%;
  animation: shimmer 1s linear infinite;
}
.loader b {
  grid-row: span 2;
  width: 42px;
  height: 42px;
  border-radius: 50%;
}
.loader i {
  height: 11px;
  border-radius: 999px;
}
.loader i:last-child { width: 72%; }
@keyframes shimmer { to { background-position: -220% 0; } }
